//! bench-hope-jar-foil — the jar ON the FOIL hot path, end to end.
//!
//! Measures the real integrated operation the new `FoilRuntimeConfig::pump_entropy`
//! performs: discharge predicted keys from the E8 jar and feed them into FOIL's
//! async loser cache via the CERTIFIED admit gate. Confirms:
//!   1. laminar (cost < Reynolds) admits 0 — no hot-path overhead when cheap,
//!   2. turbulent (cost ≥ Reynolds) throughput of predicted-key admission.
//! Release-only.

use distributed_inference::gnosis_foil::foil_entropy_boost_admit_predicted_certified;
use distributed_inference::hope_jar_e8::HopeJarE8;
use std::hint::black_box;
use std::time::Instant;

const REYNOLDS_NS: u64 = 10_000;
const BATCH: usize = 5469; // a Monster lane's worth of predicted keys per request

fn main() {
    let e8_bytes = std::fs::read("rknots/hope-jar-e8.rknot").expect("rknots/hope-jar-e8.rknot");
    let e8 = HopeJarE8::decode_rknot(&e8_bytes).expect("e8");

    // ── laminar: certified cost below the Reynolds number → gate stays shut ──
    let keys: Vec<u64> = e8.discharge_iter(0, 0).take(BATCH).collect();
    let laminar_admitted =
        foil_entropy_boost_admit_predicted_certified(&keys, 2, 1_000, REYNOLDS_NS - 1);

    // ── turbulent: above Reynolds → discharge + admit, measured end to end ──
    let requests = 20_000usize;
    let mut offered = 0u64;
    let mut admitted = 0usize;
    let t = Instant::now();
    for r in 0..requests {
        let phase = (r % 30) as u8;
        let lane = ((r / 30) % 240) as u8;
        let batch: Vec<u64> = e8.discharge_iter(phase, lane).take(BATCH).collect();
        offered += batch.len() as u64;
        let shell = (r % 4) as u8;
        admitted +=
            foil_entropy_boost_admit_predicted_certified(&batch, shell, 50_000, 5 * REYNOLDS_NS);
    }
    let dur = t.elapsed();
    black_box(admitted);

    let offered_per_s = offered as f64 / dur.as_secs_f64();
    let per_request_us = dur.as_nanos() as f64 / requests as f64 / 1000.0;

    println!("=== Hope Jar E8 → FOIL hot path (release) ===\n");
    println!(
        "operation: discharge {} predicted keys -> certified FOIL admit\n",
        BATCH
    );
    println!("-- laminar (cost < Reynolds {}) --", REYNOLDS_NS);
    println!(
        "  admitted             : {}  (gate shut — no hot-path cost when cheap)",
        laminar_admitted
    );
    println!();
    println!(
        "-- turbulent (cost = 5x Reynolds), {} requests --",
        requests
    );
    println!("  predicted keys offered : {}", offered);
    println!(
        "  predicted keys admitted: {} ({:.1}%)",
        admitted,
        admitted as f64 / offered as f64 * 100.0
    );
    println!(
        "  offer throughput       : {:.0} M keys/s",
        offered_per_s / 1e6
    );
    println!("  per request (discharge+admit): {:.3} us", per_request_us);
    println!();
    println!("the jar is now ON the hot path: turbulent requests pull predicted keys");
    println!("from the latent E8 generator and prime FOIL's async loser cache;");
    println!("laminar requests pay nothing (certified gate, never-yellow).");
}
